private async executeWithFallback(primaryManifest, request, sessionId, startTime) {
  let currentManifest = primaryManifest;
  let fallbackAttempts = 0;
  let lastError: AgentAdapterError | undefined;
  const attemptedProviders = new Set<string>();
  while (currentManifest) {
    attemptedProviders.add(currentManifest.providerId);
    try {
      return await this.providerInvoker(...);
    } catch (error) {
      // classify error
      if (agentError.category !== 'transient' || !this.enableFallback) { throw; }
      if (fallbackAttempts >= this.maxFallbackAttempts) { throw; }
      const fallbackProviderId = currentManifest.fallbackProvider;
      if (!fallbackProviderId) { throw; }
      const fallbackManifest = ...;
      if (!fallbackManifest) { throw; }
      if (attemptedProviders.has(fallbackManifest.providerId)) { throw; }  // cycle
      if (agentError.retryAfterSeconds) { await this.sleep(...); }
      fallbackAttempts += 1;
      currentManifest = fallbackManifest;
    }
  }
  throw lastError ?? ...
}
--- code end ---

The `executeWithFallback` method (lines 225-328 in AgentAdapter.ts) contains a while-loop with 5 independent throw conditions inside the catch block, mutable loop variables (`currentManifest`, `fallbackAttempts`), and side-effectful sleep. Cyclomatic complexity is approximately 10 within a 103-line method.

