export async function acquireLock(runDir: string, options: LockOptions = {}): Promise<void> {
  // destructure options
  while (Date.now() - startTime < timeout) {
    try {
      await fs.writeFile(lockPath, ..., { flag: 'wx' });
      return;
    } catch (error: unknown) {
      if (!(error && 'code' in error && error.code === 'EEXIST')) {
        throw wrapError(error, ...);
      }
      if (await isLockStale(lockPath)) {
        await removeStaleLock(lockPath);
        continue;
      }
      await sleep(pollInterval);
    }
  }
  throw new Error(...);
}
--- code end ---

The `acquireLock` function (lines 383-424 in runDirectoryManager.ts) uses a `while (Date.now() - startTime < timeout)` spin-poll loop with a try-catch inside, error-code inspection inside the catch, and async stale-lock removal mid-loop. The `isLockStale` call itself reads and parses a file. Cyclomatic complexity is approximately 7, acceptable in isolation but this is a critical path function called before every manifest update.

