private classifyError(error: unknown): AgentErrorCategory {
  if (error instanceof Error) {
    const message = error.message.toLowerCase();
    if (message.includes('timeout') || message.includes('rate limit') ||
        message.includes('503') || message.includes('429') ||
        message.includes('network') || message.includes('connection')) {
      return 'transient';
    }
    if (message.includes('ambiguous') || message.includes('policy violation') || ...) {
      return 'humanAction';
    }
    return 'permanent';
  }
  return 'permanent';
}
--- code end ---

The `classifyError` method (lines 491-523 in AgentAdapter.ts) uses 6 `||`-chained string includes for the transient category and 4 for the humanAction category. There is no separation between HTTP status codes (numeric strings '503', '429') and natural-language error substrings. This pattern is fragile and will grow as more error patterns are discovered.

