function determineExitCode(checks: DiagnosticCheck[]): { exitCode: number; status: ... } {
  const failed = checks.filter((c) => c.status === 'fail');
  const hasCredentialFailure = failed.some(
    (c) => c.name.includes('Token') || c.name.includes('API Key') || c.name.includes('Credential')
  );
  const hasEnvironmentFailure = failed.some(
    (c) => c.name.includes('Node') || c.name.includes('Git') ||
            c.name.includes('Docker') || c.name.includes('Filesystem')
  );
  const hasConfigFailure = failed.some((c) => c.name.includes('Config'));
  if (hasCredentialFailure) return { exitCode: 30, ... };
  if (hasEnvironmentFailure) return { exitCode: 20, ... };
  if (hasConfigFailure) return { exitCode: 10, ... };
  return { exitCode: 1, ... };
}
--- code end ---

The `determineExitCode` function (lines 50-77 in doctor.ts) derives exit-code priority by matching check names using `String.includes()`. Adding a new check category requires updating this function's string patterns rather than a type on the check itself. The function has 5 conditional branches.

