async function isLockStale(lockPath: string): Promise<boolean> {
  try {
    const content = await fs.readFile(lockPath, 'utf-8');
    const parsed: unknown = JSON.parse(content);
    if (!isLockFilePayload(parsed)) { return true; }
    const lockData: LockFile = parsed;
    if (Date.now() - new Date(lockData.acquired_at).getTime() > STALE_LOCK_THRESHOLD_MS) {
      return true;
    }
    const running = isProcessRunning(lockData.pid);
    return running === false;
  } catch {
    return true;
  }
}
--- code end ---

The `isLockStale` function (lines 496-516 in runDirectoryManager.ts) performs 4 distinct operations: I/O read, JSON parse, type validation, and process existence check. The blanket `catch { return true }` swallows all errors making debugging difficult. The function is called inside the hot `acquireLock` polling loop.

--- code begin (reference only) ---
function isProcessRunning(pid: number): boolean | null {
  if (process.platform === 'win32') return null;
  try {
    process.kill(pid, 0);
    return true;
  } catch (error) {
    if (error && typeof error === 'object' && 'code' in error &&
        (error as NodeJS.ErrnoException).code === 'ESRCH') {
      return false;
    }
    throw wrapError(error, `check if lock process ${pid} exists`);
  }
}
--- code end ---

The `isProcessRunning` function (lines 478-494) uses the `process.kill(pid, 0)` sentinel pattern which is a well-known Unix idiom but relies on throw-for-control-flow. The cast `(error as NodeJS.ErrnoException)` after the `'code' in error` guard is redundant. The tri-state `boolean | null` return type adds cognitive load for callers.

